<?php

/**
 * ApFormsTable
 * 
 * This class has been auto-generated by the Doctrine ORM Framework
 */
class ApFormsTable extends Doctrine_Table
{
    /**
     * Returns an instance of this class.
     *
     * @return ApFormsTable The table instance
     */
    public static function getInstance()
    {
        return Doctrine_Core::getTable('ApForms');
    }

    public static function getForms()
    {
        $forms = array();

        $forms[0] = "";

        $q = Doctrine_Query::create()
           ->from("ApForms a")
           ->where("a.form_type = 1 || a.form_type = 0")
           ->andWhere("a.form_active = 1")
           ->orderBy("a.form_name ASC");
        $ap_forms = $q->execute();

        foreach($ap_forms as $ap_form)
        {
            $forms[$ap_form->getFormId()] =  $ap_form->getFormName();
        }

        return $forms;
    }

    public static function getExtraForms()
    {
        $forms = array();

        $forms[0] = "";

        $q = Doctrine_Query::create()
           ->from("ApForms a")
           ->where("a.form_type <> 2")
           ->andWhere("a.form_active = 1")
           ->orderBy("a.form_name ASC");
        $ap_forms = $q->execute();

        foreach($ap_forms as $ap_form)
        {
            $forms[$ap_form->getFormId()] =  $ap_form->getFormName();
        }

        return $forms;
    }
	public function getAllApplicationForms($form_type=0)
	{
		//OTB FIX Show active forms
		$q=$this->createQuery('a')
		   ->where('a.form_type = ? and a.form_active = ?',array($form_type,1))
		   ->orderBy("a.form_name ASC");
		$apforms = $q->fetchArray();
		//error_log(print_r($apforms,true));
		$forms=array(0 => '');
		foreach($apforms as $form)
		{	
			$forms[$form['form_id']] = $form['form_name'];

		}
		//error_log(print_r($forms,true));
		return $forms;
	}
}